# 6. Audio and Video Data
# When you play an MP3 or MP4 file, Python reads chunks of bytes:
from pathlib import Path

video_path = Path(__file__).parent / "video.mp4"

with open(video_path, "rb") as file:
    chunks = file.read(1024)

print(type(chunks)) # <class 'bytes'>
print(chunks)
